"use strict";parserFactory.register("boylove.cc",()=>new BoyloveParser);class BoyloveParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("ul#playlist__item_title_1_url li:not(.chapterOff) a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("section.reader-cartoon-chapter")}extractTitleImpl(e){return e.querySelector("div.stui-content div.title")}findChapterTitle(e){return e.querySelector("div.title")}findCoverImageUrl(e){let r=e.querySelector("div.stui-content__thumb [style*=background-image]");return"https://boylove.cc"+util.extractUrlFromBackgroundImage(r)}preprocessRawDom(e){util.resolveLazyLoadedImages(e,"article img.lazy","data-original")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("p.desc")]}}